'use strict';
// Backend/routes/assetCardRoute.js
const express = require('express');
const router  = express.Router();
const { query } = require('../config/db');

const AERIAL_PHOTO = "data:image/png;base64,";
const FRONT_PHOTO  = "data:image/png;base64,";

router.get('/:allocationId', async (req, res) => {
  try {
    const { allocationId } = req.params;
    const result = await query(
      `SELECT al.allocation_id, al.asset_id, al.emp_id, al.emp_name, al.emp_email,
         al.department, al.client, al.project, al.accessories, al.allocation_date,
         al.status, al.mobile_no, al.photo_url, al.delivery_method,
         al.prepared_by, al.damage_photos,
         ast.brand, ast.model, ast.config, ast.serial,
         ast.processor, ast.ram, ast.storage,
         ast.warranty_start, ast.warranty_end, ast.vendor, ast.location
       FROM allocations al
       LEFT JOIN assets ast ON ast.asset_id = al.asset_id
       WHERE al.allocation_id = $1`,
      [allocationId]
    );
    if (!result.rows.length) return res.status(404).send(notFoundPage());
    res.setHeader('Content-Type', 'text/html; charset=utf-8');
    res.send(buildCardPage(result.rows[0]));
  } catch (err) {
    console.error('Card page error:', err);
    res.status(500).send(errorPage());
  }
});

function buildCardPage(d) {
  const accessories = Array.isArray(d.accessories) && d.accessories.length ? d.accessories : [];
  const statusColor = d.status === 'Active' ? '#16a34a' : '#64748b';
  const statusBg    = d.status === 'Active' ? '#dcfce7' : '#f1f5f9';
  const allocDate   = d.allocation_date
    ? new Date(d.allocation_date).toLocaleDateString('en-IN', { day:'numeric', month:'long', year:'numeric' }) : '—';
  const warrantyEnd = d.warranty_end
    ? new Date(d.warranty_end).toLocaleDateString('en-IN', { day:'numeric', month:'long', year:'numeric' }) : '—';
  const warrantyOk  = d.warranty_end && new Date(d.warranty_end) > new Date();
  const photoHtml   = d.photo_url && d.photo_url.startsWith('data:image')
    ? `<img src="${d.photo_url}" alt="${d.emp_name}" class="emp-photo" />`
    : `<div class="emp-photo-placeholder">${getInitials(d.emp_name)}</div>`;

  let damagePhotos = [];
  try { damagePhotos = JSON.parse(d.damage_photos || '[]'); } catch(_) {}

  // ── AERIAL_PHOTO and FRONT_PHOTO are the same base64 strings as before ──
  // They are used both for the page background AND the banner hover switcher.

  return `<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1.0"/>
  <title>Asset Card — ${escapeHtml(d.asset_id)} | ${escapeHtml(d.emp_name)}</title>
  <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{
      font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Arial,sans-serif;
      min-height:100vh;
      display:flex;flex-direction:column;align-items:center;
      padding:24px 0 48px;
      position:relative;
    }

    /* ════════════════════════════════════
       FULL-PAGE AERIAL BACKGROUND
       The aerial photo is blurred + dimmed
       and fixed behind the whole page.
       ════════════════════════════════════ */
   .page-bg{
      position:fixed;
      inset:0;
      z-index:-1;
      overflow:hidden;
    }
    .page-bg-img{
      width:100%;
      height:100%;
      object-fit:cover;
      object-position:center;
      /* REMOVED: filter:blur(4px) brightness(0.50) saturate(0.65); */
      display:block;
    }
    .page-bg-overlay{
      position:absolute;
      inset:0;
      background:linear-gradient(
        135deg,
        rgba(0,0,0,0.65) 0%,
        rgba(0,0,0,0.5) 50%,
        rgba(0,0,0,0.7) 100%
      );
    }
    /* ── Building banner (top of card) ── */
    .building-wrap{
      width:100%;max-width:520px;
      position:relative;height:200px;overflow:hidden;
      cursor:pointer;
      border-radius:16px 16px 0 0;
    }
    .building-aerial{width:100%;height:100%;object-fit:cover;object-position:center;
                     display:block;transition:opacity .4s}
    .building-front{width:100%;height:100%;object-fit:cover;object-position:center;
                    position:absolute;inset:0;opacity:0;transition:opacity .4s}
    .building-wrap:hover .building-front{opacity:1}
    .building-wrap:hover .building-aerial{opacity:0}
    .building-overlay{
      position:absolute;inset:0;
      background:linear-gradient(to bottom,rgba(0,0,0,.10) 0%,rgba(0,0,0,.58) 100%);
      display:flex;flex-direction:column;justify-content:flex-end;
      padding:14px 20px;pointer-events:none
    }
    .company-name{color:#fff;font-size:20px;font-weight:900;letter-spacing:.08em;
                  text-shadow:0 1px 4px rgba(0,0,0,.5)}
    .company-tag{color:rgba(255,255,255,.85);font-size:11px;margin-top:2px;
                 text-shadow:0 1px 3px rgba(0,0,0,.4)}
    .hover-hint{
      position:absolute;top:10px;left:50%;transform:translateX(-50%);
      background:rgba(0,0,0,.45);color:#fff;font-size:9px;
      padding:3px 10px;border-radius:20px;
      opacity:0;transition:opacity .3s;pointer-events:none;
      white-space:nowrap;backdrop-filter:blur(4px)
    }
    .building-wrap:hover .hover-hint{opacity:1}
    .asset-badge{
      position:absolute;top:12px;right:14px;
      background:rgba(0,0,0,.55);border:1px solid rgba(255,255,255,.35);
      border-radius:10px;padding:6px 14px;text-align:right;
      backdrop-filter:blur(8px)
    }
    .asset-badge-label{color:rgba(255,255,255,.7);font-size:9px;
                       text-transform:uppercase;letter-spacing:.1em;display:block}
    .asset-badge-id{color:#fff;font-size:20px;font-weight:800;
                    font-family:monospace;display:block;margin-top:1px}

    /* ── Card panel ── */
    .card{
      background:rgba(255,255,255,0.97);
      width:100%;max-width:520px;
      box-shadow:
        0 20px 60px rgba(0,0,0,0.40),
        0 4px 16px rgba(0,0,0,0.18),
        inset 0 1px 0 rgba(255,255,255,0.9);
      border-radius:0 0 16px 16px;
      /* subtle glass border on sides/bottom */
      border:1px solid rgba(255,255,255,0.5);
      border-top:none;
    }

    /* ── Employee header ── */
    .emp-header{
      background:linear-gradient(135deg,#1d3461 0%,#1d5c3c 100%);
      padding:20px 22px;display:flex;align-items:center;gap:16px
    }
    .emp-photo{width:68px;height:68px;border-radius:50%;object-fit:cover;
               border:3px solid rgba(255,255,255,.5);flex-shrink:0}
    .emp-photo-placeholder{
      width:68px;height:68px;border-radius:50%;flex-shrink:0;
      background:rgba(255,255,255,.2);border:3px solid rgba(255,255,255,.4);
      display:flex;align-items:center;justify-content:center;
      color:#fff;font-size:22px;font-weight:700
    }
    .emp-name{color:#fff;font-size:19px;font-weight:700}
    .emp-meta{color:rgba(255,255,255,.75);font-size:12px;margin-top:3px}
    .status-pill{
      display:inline-block;
      background:${statusBg};color:${statusColor};
      font-size:10px;font-weight:700;
      padding:3px 10px;border-radius:20px;
      margin-top:6px;text-transform:uppercase;letter-spacing:.05em
    }

    /* ── Section ── */
    .section{padding:16px 20px;border-bottom:1px solid #f1f5f9}
    .section:last-child{border-bottom:none}
    .sec-label{
      font-size:9px;font-weight:800;text-transform:uppercase;
      letter-spacing:.12em;color:#1d5c3c;
      margin-bottom:12px;display:flex;align-items:center;gap:8px
    }
    .sec-label::after{content:'';flex:1;height:1px;background:#e2e8f0}

    /* ── Info grid ── */
    .info-grid{display:grid;grid-template-columns:1fr 1fr;gap:8px}
    .info-item{background:#f8fafc;border-radius:10px;padding:10px 12px;border:1px solid #f1f5f9}
    .info-item.full{grid-column:1/-1}
    .info-key{font-size:10px;color:#94a3b8;font-weight:600;
              text-transform:uppercase;letter-spacing:.05em;margin-bottom:3px}
    .info-val{font-size:13px;color:#1e293b;font-weight:700;line-height:1.3}
    .info-val.mono{font-family:monospace;font-size:12px;color:#1d5c3c}
    .info-val.ok{color:#16a34a}
    .info-val.exp{color:#dc2626}

    /* ── Accessories ── */
    .acc-wrap{display:flex;flex-wrap:wrap;gap:6px}
    .acc-chip{
      background:#f0fdf4;color:#14532d;
      border:1px solid #bbf7d0;border-radius:20px;
      font-size:11px;font-weight:600;padding:4px 10px
    }

    /* ── Damage photos ── */
    .photos-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:8px}
    .photo-thumb{
      width:100%;aspect-ratio:1;object-fit:cover;
      border-radius:8px;cursor:pointer;
      border:2px solid #e2e8f0;transition:border-color .2s
    }
    .photo-thumb:hover{border-color:#1d5c3c}

    /* ── Lightbox ── */
    .lightbox{
      display:none;position:fixed;inset:0;
      background:rgba(0,0,0,.88);z-index:1000;
      align-items:center;justify-content:center;padding:16px
    }
    .lightbox.open{display:flex}
    .lightbox img{max-width:100%;max-height:90vh;border-radius:10px;
                  box-shadow:0 20px 60px rgba(0,0,0,.6)}
    .lightbox-close{
      position:absolute;top:16px;right:20px;
      color:#fff;font-size:28px;cursor:pointer;line-height:1;
      background:rgba(0,0,0,.4);width:36px;height:36px;
      border-radius:50%;display:flex;align-items:center;justify-content:center
    }

    /* ── Footer ── */
    .card-footer{
      background:#f8fafc;padding:14px 20px;
      border-top:2px solid #1d5c3c;
      text-align:center;border-radius:0 0 16px 16px
    }
    .footer-brand{font-size:13px;font-weight:900;color:#1d3461;letter-spacing:.06em}
    .footer-text{font-size:11px;color:#94a3b8;margin-top:3px;line-height:1.6}
    .scan-note{font-size:9px;color:#cbd5e1;margin-top:5px;font-family:monospace}

    @media(max-width:520px){
      .info-grid{grid-template-columns:1fr}
      .info-item.full{grid-column:1}
      .building-wrap{height:155px;border-radius:0}
      .photos-grid{grid-template-columns:repeat(2,1fr)}
      body{padding-top:0}
    }
  </style>
</head>
<body>

<!-- ════ Full-page blurred aerial background ════ -->
<div class="page-bg">
  <img class="page-bg-img" src="${AERIAL_PHOTO}" alt=""/>
  <div class="page-bg-overlay"></div>
</div>

<!-- ════ Building Banner ════ -->
<div class="building-wrap" onclick="openLightbox('${AERIAL_PHOTO}')">
  <img class="building-aerial" src="${AERIAL_PHOTO}" alt="Mindteck aerial view"/>
  <img class="building-front"  src="${FRONT_PHOTO}"  alt="Mindteck front view"/>
  <div class="building-overlay">
    <div class="company-name">MINDTECK</div>
    <div class="company-tag">IT Asset Management System</div>
  </div>
  <span class="hover-hint">Click to enlarge · Hover for front view</span>
  <div class="asset-badge">
    <span class="asset-badge-label">Asset No</span>
    <span class="asset-badge-id">${escapeHtml(d.asset_id)}</span>
  </div>
</div>

<!-- ════ Card ════ -->
<div class="card">

  <!-- Employee -->
  <div class="emp-header">
    ${photoHtml}
    <div>
      <div class="emp-name">${escapeHtml(d.emp_name)}</div>
      <div class="emp-meta">${escapeHtml(d.emp_id || '')} · ${escapeHtml(d.department || '')}</div>
      <span class="status-pill">${escapeHtml(d.status || 'Active')}</span>
    </div>
  </div>

  <!-- Laptop Details -->
  <div class="section">
    <div class="sec-label">💻 Laptop Details</div>
    <div class="info-grid">
      <div class="info-item"><div class="info-key">Brand</div><div class="info-val">${escapeHtml(d.brand) || '—'}</div></div>
      <div class="info-item"><div class="info-key">Model</div><div class="info-val">${escapeHtml(d.model) || '—'}</div></div>
      <div class="info-item full"><div class="info-key">Configuration</div><div class="info-val">${escapeHtml(d.config) || '—'}</div></div>
      <div class="info-item full"><div class="info-key">Serial Number</div><div class="info-val mono">${escapeHtml(d.serial) || '—'}</div></div>
      ${d.processor ? `<div class="info-item"><div class="info-key">Processor</div><div class="info-val">${escapeHtml(d.processor)}</div></div>` : ''}
      ${d.ram       ? `<div class="info-item"><div class="info-key">RAM</div><div class="info-val">${escapeHtml(d.ram)}</div></div>` : ''}
      ${d.storage   ? `<div class="info-item"><div class="info-key">Storage</div><div class="info-val">${escapeHtml(d.storage)}</div></div>` : ''}
    </div>
  </div>

  <!-- Allocation Details -->
  <div class="section">
    <div class="sec-label">📋 Allocation Details</div>
    <div class="info-grid">
      <div class="info-item"><div class="info-key">Allocation Date</div><div class="info-val">${allocDate}</div></div>
      <div class="info-item"><div class="info-key">Allocation ID</div><div class="info-val mono" style="font-size:10px">${escapeHtml(d.allocation_id)}</div></div>
      ${d.project ? `<div class="info-item"><div class="info-key">Project</div><div class="info-val">${escapeHtml(d.project)}</div></div>` : ''}
      ${d.client  ? `<div class="info-item"><div class="info-key">Client</div><div class="info-val">${escapeHtml(d.client)}</div></div>` : ''}
      <div class="info-item">
        <div class="info-key">Warranty Until</div>
        <div class="info-val ${warrantyOk ? 'ok' : 'exp'}">${warrantyEnd} ${warrantyOk ? '✓' : '⚠ Expired'}</div>
      </div>
      ${d.prepared_by ? `<div class="info-item"><div class="info-key">Prepared By</div><div class="info-val">${escapeHtml(d.prepared_by)}</div></div>` : ''}
      ${d.location    ? `<div class="info-item"><div class="info-key">Location</div><div class="info-val">${escapeHtml(d.location)}</div></div>` : ''}
    </div>
  </div>

  <!-- Accessories -->
  ${accessories.length ? `
  <div class="section">
    <div class="sec-label">📦 Accessories Included</div>
    <div class="acc-wrap">
      ${accessories.map(a => `<span class="acc-chip">✓ ${escapeHtml(a)}</span>`).join('')}
    </div>
  </div>` : ''}

  <!-- Damage / Condition Photos -->
  ${damagePhotos.length ? `
  <div class="section">
    <div class="sec-label">📷 Condition Photos</div>
    <div class="photos-grid">
      ${damagePhotos.map((src, i) => `
        <img class="photo-thumb" src="${escapeHtml(src)}" alt="Photo ${i+1}"
             onclick="openLightbox('${escapeHtml(src)}')" />`).join('')}
    </div>
  </div>` : ''}

  <!-- Contact -->
  <div class="section">
    <div class="sec-label">📞 Contact</div>
    <div class="info-grid">
      <div class="info-item full">
        <div class="info-key">Work Email</div>
        <div class="info-val" style="font-size:12px">${escapeHtml(d.emp_email) || '—'}</div>
      </div>
      ${d.mobile_no ? `<div class="info-item full"><div class="info-key">Mobile</div><div class="info-val">${escapeHtml(d.mobile_no)}</div></div>` : ''}
    </div>
  </div>

  <!-- Footer -->
  <div class="card-footer">
    <div class="footer-brand">MINDTECK</div>
    <div class="footer-text">IT Asset Management · sysadmin@mindteck.us</div>
    <div class="scan-note">Scanned · ${new Date().toLocaleDateString('en-IN')} · ${escapeHtml(d.allocation_id)}</div>
  </div>

</div><!-- /.card -->

<!-- Lightbox -->
<div class="lightbox" id="lb" onclick="closeLightbox()">
  <div class="lightbox-close" onclick="closeLightbox()">✕</div>
  <img id="lb-img" src="" alt="Full view"/>
</div>

<script>
  function openLightbox(src) {
    document.getElementById('lb-img').src = src;
    document.getElementById('lb').classList.add('open');
    event && event.stopPropagation();
  }
  function closeLightbox() {
    document.getElementById('lb').classList.remove('open');
    document.getElementById('lb-img').src = '';
  }
  document.addEventListener('keydown', e => { if(e.key==='Escape') closeLightbox(); });
</script>
</body>
</html>`;
}

function escapeHtml(str) {
  if (!str) return '';
  return str
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;').replace(/'/g, '&#39;');
}

function getInitials(name) {
  if (!name) return '?';
  return name.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase();
}

function notFoundPage() {
  return `<!DOCTYPE html><html><head><meta charset="UTF-8"/>
  <meta name="viewport" content="width=device-width,initial-scale=1"/>
  <title>Not Found</title>
  <style>body{font-family:Arial,sans-serif;background:#0a1828;display:flex;align-items:center;
  justify-content:center;min-height:100vh}
  .box{background:#fff;border-radius:16px;padding:40px;text-align:center;max-width:360px;
  box-shadow:0 8px 24px rgba(0,0,0,.3)}h2{color:#1e293b}p{color:#64748b;font-size:14px;margin-top:8px}</style>
  </head><body><div class="box">
  <div style="font-size:48px">🔍</div>
  <h2 style="margin-top:16px">Asset Not Found</h2>
  <p>This QR code does not match any asset.</p>
  <p style="margin-top:12px;font-size:12px;color:#94a3b8">sysadmin@mindteck.us</p>
  </div></body></html>`;
}

function errorPage() {
  return `<!DOCTYPE html><html><head><meta charset="UTF-8"/><title>Error</title>
  <style>body{font-family:Arial,sans-serif;background:#0a1828;display:flex;align-items:center;
  justify-content:center;min-height:100vh}
  .box{background:#fff;border-radius:16px;padding:40px;text-align:center;max-width:360px}</style>
  </head><body><div class="box">
  <div style="font-size:48px">⚠️</div>
  <h2 style="color:#1e293b;margin-top:16px">Something went wrong</h2>
  <p style="color:#64748b;font-size:14px;margin-top:8px">Please try again or contact IT.</p>
  </div></body></html>`;
}

module.exports = router;